static const int N_TEST = sizeof(TEST_DATA) / sizeof(TEST_DATA[0]);


// ── Accuracy measurement ─────────────────────────────────────────────────
int main() {
    int correct       = 0;
    int pred_open     = 0;
    int pred_closed   = 0;
    int true_open     = 0;
    int true_closed   = 0;
    int tp = 0, tn = 0, fp = 0, fn = 0;  // Closed=positive class

    std::cout << "=== RF EEG Accuracy Test — " << N_TEST << " samples ===" << std::endl;

    for (int s = 0; s < N_TEST; s++) {
        // ── Pack features ────────────────────────────────────────────────
        feature_t feat[NUM_FEATURES];
        for (int f = 0; f < NUM_FEATURES; f++) {
            feat[f] = (feature_t)TEST_DATA[s][f];   // already offset-subtracted
        }
        int true_label = (int)TEST_DATA[s][NUM_FEATURES];

        // ── BUG 1 FIX: flush window before each independent sample ────────
        feature_t dummy[NUM_FEATURES];
        for (int f = 0; f < NUM_FEATURES; f++) dummy[f] = feat[f];
        rf_top(dummy, (reset_t)1);   // reset — discard result

        // ── Real inference ────────────────────────────────────────────────
        label_t pred = rf_top(feat, (reset_t)0);
        int pred_int = (int)pred;

        // ── Bookkeeping ───────────────────────────────────────────────────
        if (pred_int == true_label) correct++;
        if (pred_int == 0) pred_open++;   else pred_closed++;
        if (true_label == 0) true_open++; else true_closed++;

        // Confusion matrix (Closed = positive)
        if      (true_label == 1 && pred_int == 1) tp++;
        else if (true_label == 0 && pred_int == 0) tn++;
        else if (true_label == 0 && pred_int == 1) fp++;
        else                                        fn++;
    }

    float accuracy   = 100.0f * correct / N_TEST;
    float precision  = (tp + fp > 0) ? 100.0f * tp / (tp + fp) : 0.0f;
    float recall     = (tp + fn > 0) ? 100.0f * tp / (tp + fn) : 0.0f;
    float f1         = (precision + recall > 0) ?
                       2.0f * precision * recall / (precision + recall) : 0.0f;
    float specificity= (tn + fp > 0) ? 100.0f * tn / (tn + fp) : 0.0f;

    std::cout << "────────────────────────────────────" << std::endl;
    std::cout << "Accuracy   : " << accuracy    << "% (" << correct << "/" << N_TEST << ")" << std::endl;
    std::cout << "Precision  : " << precision   << "% (Closed)" << std::endl;
    std::cout << "Recall     : " << recall      << "% (Closed)" << std::endl;
    std::cout << "Specificity: " << specificity << "% (Open)"   << std::endl;
    std::cout << "F1-Score   : " << f1          << std::endl;
    std::cout << "────────────────────────────────────" << std::endl;
    std::cout << "Pred Open  : " << pred_open   << "  (True: " << true_open   << ")" << std::endl;
    std::cout << "Pred Closed: " << pred_closed << "  (True: " << true_closed << ")" << std::endl;
    std::cout << "TP=" << tp << " TN=" << tn << " FP=" << fp << " FN=" << fn << std::endl;
    std::cout << "────────────────────────────────────" << std::endl;

    if (accuracy >= 90.0f) {
        std::cout << "✓ TARGET MET: accuracy >= 90%" << std::endl;
        return 0;
    } else {
        std::cout << "✗ Below 90% — see WORKFLOW comment in tb_accuracy.cpp" << std::endl;
        return 1;
    }
}
